() => {
  const checkboxEvents = {
    className: 'some-class',
    labelText: 'Checkbox label'
  };
  return <>
      <Checkbox {...checkboxEvents} id="checkbox-3" helperText="Helper text goes here" />
      <br /> <br />
      <Checkbox {...checkboxEvents} id="checkbox-4" invalid invalidText="Invalid text goes here" />
      <br /> <br />
      <Checkbox {...checkboxEvents} id="checkbox-5" warn warnText="Warning text goes here" />
      <br /> <br />
      <Checkbox {...checkboxEvents} id="checkbox-6" readOnly />
    </>;
}

() => {
  return <CheckboxSkeleton />;
}

